 47→describe('cleanTitle', () => {
 48→  it('strips prefixes like "help me", "can you", "please"', () => {
 49→    expect(cleanTitle('help me fix the login bug')).toBe('Fix the login bug');
 50→    expect(cleanTitle('can you update the readme')).toBe('Update the readme');
 51→    expect(cleanTitle('please add a new feature')).toBe('Add a new feature');
 52→  });
 53→
 54→  it('strips greeting prefixes', () => {
 55→    expect(cleanTitle('hi, fix the bug')).toBe('Fix the bug');
 56→    expect(cleanTitle('hello fix the bug')).toBe('Fix the bug');
 57→    expect(cleanTitle('hey, can you help')).toBe('Can you help');
 58→  });
 59→
 60→  it('strips markdown characters (* _ ` #)', () => {
 61→    expect(cleanTitle('**bold** title')).toBe('Bold title');
 62→    expect(cleanTitle('`code` title')).toBe('Code title');
 63→    expect(cleanTitle('## heading')).toBe('Heading');
 64→  });
 65→
 66→  it('truncates to 60 characters with ellipsis', () => {
 67→    const longTitle = 'A'.repeat(70);
 68→    const result = cleanTitle(longTitle);
 69→    expect(result.length).toBe(60);
 70→    expect(result.endsWith('...')).toBe(true);
 71→  });
 72→
 73→  it('does not truncate titles at 60 characters or under', () => {
 74→    const exactTitle = 'A'.repeat(60);
 75→    expect(cleanTitle(exactTitle)).toBe(exactTitle);
