 1→import { describe, it, expect } from 'vitest';
 2→import { levenshtein, findSimilarNames } from './fuzzy-match.js';
 3→
 4→describe('levenshtein', () => {
 5→  it('returns 0 for identical strings', () => {
 6→    expect(levenshtein('hello', 'hello')).toBe(0);
 7→  });
 8→
 9→  it('returns length of other string when one is empty', () => {
10→    expect(levenshtein('', 'abc')).toBe(3);
11→    expect(levenshtein('abc', '')).toBe(3);
12→  });
13→
14→  it('returns 0 for two empty strings', () => {
15→    expect(levenshtein('', '')).toBe(0);
16→  });
17→
18→  it('returns 1 for a single substitution', () => {
19→    expect(levenshtein('cat', 'bat')).toBe(1);
20→  });
21→
22→  it('returns 1 for a single insertion', () => {
23→    expect(levenshtein('cat', 'cats')).toBe(1);
24→  });
25→
26→  it('returns 1 for a single deletion', () => {
27→    expect(levenshtein('cats', 'cat')).toBe(1);
28→  });
29→
30→  it('handles completely different strings', () => {
31→    expect(levenshtein('abc', 'xyz')).toBe(3);
32→  });
33→
34→  it('handles transposition as two operations', () => {
35→    // Standard Levenshtein counts transposition as 2 (delete + insert or sub + sub)
36→    expect(levenshtein('ab', 'ba')).toBe(2);
37→  });
38→});
