40→describe('findSimilarNames', () => {
41→  const candidates = ['code-insights', 'my-project', 'dashboard', 'server-api'];
42→
43→  it('returns exact match first', () => {
44→    const result = findSimilarNames('dashboard', candidates);
45→    expect(result[0]).toBe('dashboard');
46→  });
47→
48→  it('returns close matches within default maxDistance', () => {
49→    const result = findSimilarNames('dashbord', candidates);
50→    expect(result).toContain('dashboard');
51→  });
52→
53→  it('returns empty array when no matches within maxDistance', () => {
54→    const result = findSimilarNames('completely-unrelated-name', candidates, 2);
55→    expect(result).toEqual([]);
56→  });
57→
58→  it('is case-insensitive', () => {
59→    const result = findSimilarNames('DASHBOARD', candidates);
60→    expect(result).toContain('dashboard');
61→  });
62→
63→  it('respects custom maxDistance', () => {
64→    // 'dashbord' -> 'dashboard' has distance 1
65→    const strict = findSimilarNames('dashbord', candidates, 0);
66→    expect(strict).not.toContain('dashboard');
67→
68→    const relaxed = findSimilarNames('dashbord', candidates, 1);
69→    expect(relaxed).toContain('dashboard');
70→  });
71→
72→  it('sorts results by distance (closest first)', () => {
73→    const result = findSimilarNames('server', ['server-api', 'serve', 'observer', 'something-else'], 5);
74→    // 'serve' (distance 1) should come before 'server-api' (distance 4)
75→    const serveIdx = result.indexOf('serve');
76→    const serverApiIdx = result.indexOf('server-api');
77→    expect(serveIdx).toBeLessThan(serverApiIdx);
78→  });
79→
80→  it('returns empty array for empty candidates', () => {
81→    expect(findSimilarNames('test', [])).toEqual([]);
82→  });
83→});
