{
  "summary": {
    "title": "Implemented auth",
    "content": "Added login and logout",
    "bullets": ["Login flow", "Logout flow"]
  },
  "decisions": [],
  "learnings": []
}
</json>`;
    const result = parseAnalysisResponse(response);
