describe('parsePromptQualityResponse', () => {
  it('parses valid prompt quality response', () => {
    const response = `<json>{
      "efficiencyScore": 85,
      "potentialMessageReduction": 2,
      "overallAssessment": "Good prompting style",
      "wastedTurns": [],
      "antiPatterns": [],
