152→/**
153→ * Get the most recent session matching optional filters.
154→ * Uses LIMIT 1 to avoid scanning all rows.
155→ */
156→export function getLastSession(opts?: { sourceTool?: string; projectId?: string }): SessionRow | null {
157→  const db = getDb();
158→
159→  const conditions: string[] = [];
160→  const params: (string | number)[] = [];
161→
162→  if (opts?.sourceTool) {
163→    conditions.push('source_tool = ?');
164→    params.push(opts.sourceTool);
165→  }
166→  if (opts?.projectId) {
167→    conditions.push('project_id = ?');
168→    params.push(opts.projectId);
169→  }
170→
171→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
172→  const sql = `
173→    SELECT
174→      id, project_id, project_name,
175→      started_at, ended_at,
176→      message_count, user_message_count, assistant_message_count, tool_call_count,
177→      estimated_cost_usd, total_input_tokens, total_output_tokens,
178→      cache_creation_tokens, cache_read_tokens,
179→      primary_model, models_used,
180→      generated_title, custom_title, summary, session_character,
181→      source_tool, usage_source
182→    FROM sessions
183→    ${where}
184→    ORDER BY started_at DESC
185→    LIMIT 1
186→  `;
187→
188→  const row = db.prepare(sql).get(...params) as {
189→    id: string;
190→    project_id: string;
191→    project_name: string;
192→    started_at: string;
193→    ended_at: string;
194→    message_count: number;
195→    user_message_count: number;
196→    assistant_message_count: number;
197→    tool_call_count: number;
198→    estimated_cost_usd: number | null;
199→    total_input_tokens: number | null;
200→    total_output_tokens: number | null;
201→    cache_creation_tokens: number | null;
202→    cache_read_tokens: number | null;
203→    primary_model: string | null;
204→    models_used: string | null;
205→    generated_title: string | null;
206→    custom_title: string | null;
207→    summary: string | null;
208→    session_character: string | null;
209→    source_tool: string;
210→    usage_source: string | null;
211→  } | undefined;
212→
213→  if (!row) return null;
214→
215→  return {
216→    id: row.id,
217→    projectId: row.project_id,
218→    projectName: row.project_name,
219→    startedAt: new Date(row.started_at),
220→    endedAt: new Date(row.ended_at),
221→    messageCount: row.message_count,
222→    userMessageCount: row.user_message_count,
223→    assistantMessageCount: row.assistant_message_count,
224→    toolCallCount: row.tool_call_count,
225→    estimatedCostUsd: row.estimated_cost_usd ?? undefined,
226→    totalInputTokens: row.total_input_tokens ?? undefined,
227→    totalOutputTokens: row.total_output_tokens ?? undefined,
228→    cacheCreationTokens: row.cache_creation_tokens ?? undefined,
229→    cacheReadTokens: row.cache_read_tokens ?? undefined,
230→    primaryModel: row.primary_model ?? undefined,
231→    modelsUsed: parseModelsUsed(row.models_used),
232→    generatedTitle: row.generated_title ?? undefined,
233→    customTitle: row.custom_title ?? undefined,
234→    summary: row.summary ?? undefined,
235→    sessionCharacter: row.session_character ?? undefined,
236→    sourceTool: row.source_tool,
237→    usageSource: row.usage_source ?? undefined,
238→  };
239→}
