242→ * Count sessions matching optional filters without loading row data.
243→ * Use this instead of getSessions({}).length to avoid full-table scans
244→ * when only a count is needed.
245→ */
246→export function getSessionCount(opts: SessionQueryOptions = {}): number {
247→  const db = getDb();
248→
249→  const conditions: string[] = [];
250→  const params: (string | number)[] = [];
251→
252→  if (opts.periodStart) {
253→    conditions.push('started_at >= ?');
254→    params.push(opts.periodStart.toISOString());
255→  }
256→  if (opts.projectId) {
257→    conditions.push('project_id = ?');
258→    params.push(opts.projectId);
259→  }
260→  if (opts.sourceTool) {
261→    conditions.push('source_tool = ?');
262→    params.push(opts.sourceTool);
263→  }
264→
265→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
266→  const sql = `SELECT COUNT(*) AS cnt FROM sessions ${where}`;
267→
268→  const row = db.prepare(sql).get(...params) as { cnt: number };
