324→    const global = db.prepare(`
325→      SELECT
326→        COUNT(*)                       AS sessions_with_usage,
327→        SUM(total_input_tokens)        AS total_input,
328→        SUM(total_output_tokens)       AS total_output,
329→        SUM(cache_creation_tokens)     AS cache_creation,
330→        SUM(cache_read_tokens)         AS cache_read,
331→        SUM(estimated_cost_usd)        AS total_cost
332→      FROM sessions
333→      WHERE usage_source IS NOT NULL
334→    `).get() as {
335→      sessions_with_usage: number;
336→      total_input: number | null;
337→      total_output: number | null;
338→      cache_creation: number | null;
339→      cache_read: number | null;
340→      total_cost: number | null;
341→    };
342→
343→    // Upsert the singleton usage_stats row
344→    db.prepare(`
345→      INSERT INTO usage_stats (id, total_input_tokens, total_output_tokens, cache_creation_tokens, cache_read_tokens, estimated_cost_usd, sessions_with_usage, last_updated_at)
346→      VALUES (1, ?, ?, ?, ?, ?, ?, datetime('now'))
347→      ON CONFLICT(id) DO UPDATE SET
348→        total_input_tokens    = excluded.total_input_tokens,
349→        total_output_tokens   = excluded.total_output_tokens,
350→        cache_creation_tokens = excluded.cache_creation_tokens,
351→        cache_read_tokens     = excluded.cache_read_tokens,
352→        estimated_cost_usd    = excluded.estimated_cost_usd,
353→        sessions_with_usage   = excluded.sessions_with_usage,
354→        last_updated_at       = excluded.last_updated_at
355→    `).run(
356→      global.total_input ?? 0,
357→      global.total_output ?? 0,
358→      global.cache_creation ?? 0,
359→      global.cache_read ?? 0,
360→      global.total_cost ?? 0,
361→      global.sessions_with_usage ?? 0,
362→    );
363→
364→    // Recalculate per-project usage totals
365→    const perProject = db.prepare(`
366→      SELECT
367→        project_id,
368→        COUNT(*)                   AS session_count,
369→        SUM(total_input_tokens)    AS total_input,
370→        SUM(total_output_tokens)   AS total_output,
371→        SUM(cache_creation_tokens) AS cache_creation,
372→        SUM(cache_read_tokens)     AS cache_read,
373→        SUM(estimated_cost_usd)    AS total_cost,
374→        MAX(ended_at)              AS last_activity
375→      FROM sessions
376→      GROUP BY project_id
377→    `).all() as Array<{
378→      project_id: string;
379→      session_count: number;
380→      total_input: number | null;
381→      total_output: number | null;
382→      cache_creation: number | null;
383→      cache_read: number | null;
384→      total_cost: number | null;
385→      last_activity: string;
386→    }>;
387→
388→    const updateProject = db.prepare(`
389→      UPDATE projects SET
390→        session_count         = ?,
391→        total_input_tokens    = ?,
392→        total_output_tokens   = ?,
393→        cache_creation_tokens = ?,
394→        cache_read_tokens     = ?,
395→        estimated_cost_usd    = ?,
396→        last_activity         = ?,
397→        updated_at            = datetime('now')
398→      WHERE id = ?
399→    `);
400→
401→    for (const row of perProject) {
402→      updateProject.run(
403→        row.session_count,
404→        row.total_input ?? 0,
405→        row.total_output ?? 0,
406→        row.cache_creation ?? 0,
407→        row.cache_read ?? 0,
408→        row.total_cost ?? 0,
409→        row.last_activity,
410→        row.project_id,
411→      );
412→    }
413→
414→    return global;
415→  });
416→
417→  const result = tx() as {
418→    sessions_with_usage: number;
419→    total_input: number | null;
420→    total_output: number | null;
421→    cache_creation: number | null;
422→    cache_read: number | null;
423→    total_cost: number | null;
424→  };
425→
426→  const totalTokens = (result.total_input ?? 0) + (result.total_output ?? 0)
427→    + (result.cache_creation ?? 0) + (result.cache_read ?? 0);
428→
429→  return {
430→    sessionsWithUsage: result.sessions_with_usage ?? 0,
431→    totalTokens,
432→    estimatedCostUsd: result.total_cost ?? 0,
433→  };
434→}
435→
436→function updateGlobalUsageStats(session: ParsedSession, isForce: boolean): void {
437→  if (isForce || !session.usage) return;
438→
439→  const stmts = getStmts();
440→  stmts.upsertUsageStatsIncrement.run(
441→    session.usage.totalInputTokens,
442→    session.usage.totalOutputTokens,
443→    session.usage.cacheCreationTokens,
444→    session.usage.cacheReadTokens,
445→    session.usage.estimatedCostUsd,
446→  );
447→}
