 31→app.put('/llm', async (c) => {
 32→  const body = await c.req.json<{
 33→    dashboardPort?: number;
 34→    provider?: string;
 35→    model?: string;
 36→    apiKey?: string;
 37→    baseUrl?: string;
 38→  }>();
 39→
 40→  const config: ClaudeInsightConfig = loadConfig() ?? {
 41→    sync: { claudeDir: '', excludeProjects: [] },
 42→  };
 43→
 44→  let changed = false;
 45→
 46→  // Update dashboard port if provided
 47→  if (body.dashboardPort !== undefined) {
 48→    const port = body.dashboardPort;
 49→    if (typeof port !== 'number' || !Number.isInteger(port) || port < 1 || port > 65535) {
 50→      return c.json({ error: 'dashboardPort must be an integer between 1 and 65535' }, 400);
 51→    }
 52→    config.dashboard = { ...config.dashboard, port };
 53→    changed = true;
 54→  }
 55→
 56→  // Update LLM config if any LLM field is provided
 57→  const hasLLMField = body.provider !== undefined || body.model !== undefined ||
 58→    body.apiKey !== undefined || body.baseUrl !== undefined;
 59→
 60→  if (hasLLMField) {
 61→    if (body.provider !== undefined && !VALID_PROVIDERS.includes(body.provider as typeof VALID_PROVIDERS[number])) {
 62→      return c.json({ error: `provider must be one of: ${VALID_PROVIDERS.join(', ')}` }, 400);
 63→    }
 64→
 65→    const existingLlm = config.dashboard?.llm ?? {} as Partial<LLMProviderConfig>;
 66→
 67→    const updatedLlm: LLMProviderConfig = {
 68→      provider: (body.provider as LLMProviderConfig['provider']) ?? existingLlm.provider ?? 'ollama',
 69→      model: body.model ?? existingLlm.model ?? '',
 70→      // Preserve existing API key if not provided in update
 71→      ...(body.apiKey !== undefined
 72→        ? { apiKey: body.apiKey || undefined }
 73→        : existingLlm.apiKey !== undefined ? { apiKey: existingLlm.apiKey } : {}),
 74→      ...(body.baseUrl !== undefined
 75→        ? { baseUrl: body.baseUrl || undefined }
 76→        : existingLlm.baseUrl !== undefined ? { baseUrl: existingLlm.baseUrl } : {}),
 77→    };
 78→
 79→    if (!updatedLlm.model) {
 80→      return c.json({ error: 'model is required when setting LLM config' }, 400);
 81→    }
 82→
 83→    config.dashboard = { ...config.dashboard, llm: updatedLlm };
 84→    changed = true;
 85→  }
 86→
 87→  if (!changed) {
 88→    return c.json({ ok: true });
 89→  }
 90→
 91→  saveConfig(config);
 92→  return c.json({ ok: true });
